package main

import (
	"fmt"
	"time"

	lua "github.com/yuin/gopher-lua"
)

// luaResult holds the result of Lua script execution
type luaResult struct {
	value float64
	err   error
}

// openBase opens base Lua libraries while removing dangerous functions
func openBase(L *lua.LState) {
	// Open base libraries
	lua.OpenBase(L)

	// Remove dangerous functions
	L.SetGlobal("load", lua.LNil)
	L.SetGlobal("loadfile", lua.LNil)
	L.SetGlobal("dofile", lua.LNil)
	L.SetGlobal("print", lua.LNil)
}

// ExecutePricingScript executes user-provided Lua scripts safely
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	resultCh := make(chan luaResult, 1)

	go func() {
		defer func() {
			if r := recover(); r != nil {
				resultCh <- luaResult{0, fmt.Errorf("lua runtime panic: %v", r)}
			}
		}()

		// Create restricted Lua environment
		L := lua.NewState(lua.Options{SkipOpenLibs: true})
		defer L.Close()

		// Open safe base libraries
		openBase(L)
		// Open math library for arithmetic operations
		lua.OpenMath(L)

		// Execute user script
		if err := L.DoString(script); err != nil {
			resultCh <- luaResult{0, fmt.Errorf("script execution failed: %w", err)}
			return
		}

		// Retrieve pricing function
		fn := L.GetGlobal("calculate_final_price")
		if fn.Type() != lua.LTFunction {
			resultCh <- luaResult{0, fmt.Errorf("calculate_final_price function not found")}
			return
		}

		// Convert context to Lua table
		ctxTable := L.NewTable()
		for k, v := range ctx {
			L.SetField(ctxTable, k, lua.LNumber(v))
		}

		// Call function with context
		if err := L.CallByParam(lua.P{
			Fn:      fn,
			NRet:    1,
			Protect: true,
		}, ctxTable); err != nil {
			resultCh <- luaResult{0, fmt.Errorf("function call failed: %w", err)}
			return
		}

		// Process result
		retVal := L.Get(-1)
		L.Pop(1)

		if num, ok := retVal.(lua.LNumber); ok {
			resultCh <- luaResult{float64(num), nil}
		} else {
			resultCh <- luaResult{0, fmt.Errorf("expected numeric return value, got %s", retVal.Type())}
		}
	}()

	select {
	case res := <-resultCh:
		return res.value, res.err
	case <-time.After(5 * time.Second):
		return 0, fmt.Errorf("script execution timed out")
	}
}

