// setupSafeEnvironment sets up the Lua environment with only safe functions and libraries.
func setupSafeEnvironment(L *lua.LState) {
	// Open base library but do not open unsafe libraries (like package, io, os) and remove unsafe functions
	L.Push(L.NewFunction(lua.OpenBase))
	L.Call(0, 0)

